Here's how to handle each scenario with modern MSTest (3.9+/3.10+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MyTests
{
    // 1. Windows-only (registry access)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        // Skipped automatically on non-Windows
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_ProducesValidOutput()
    {
        // Runs locally, skipped in CI environments
        var frame = GpuRenderer.RenderFrame();
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await _weatherClient.GetForecastAsync();
        Assert.IsNotNull(forecast);
    }

    // 4. Temp file cleanup — use [TestCleanup] (runs even on failure)
    private string? _tempFile;

    [TestMethod]
    public void Export_WritesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        Exporter.WriteTo(_tempFile);
        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
            File.Delete(_tempFile);
    }
}
```

**Key points:**

| Scenario | Solution | Min version |
|----------|----------|-------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10 |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10 |
| Flaky test | `[Retry(3)]` | 3.9 |
| Guaranteed cleanup | `[TestCleanup]` method | Any |

`[TestCleanup]` always runs after each test—even on failure—so it's the right place for resource cleanup. Alternatively, implement `IDisposable` or `IAsyncDisposable` on the test class for the same guarantee.
